// NODO: Build_Error_Payload_Multilang (v3.1 - Ibrido WebApp + Telegram CORRETTO)
// OBIETTIVO: Restituire JSON di errore per WebApp E payload Telegram, rispettando le chiavi esistenti.

const input = $input.first().json;

const req = input.body.data;
const rawData = req.owner_data;

const vat = rawData.vat_number;
const chatId = req.chat_id;
const userLang = rawData.lenguage || 'en';

const SUPPORT_BOT_URL = "https://t.me/TrinAi_TecSupport_bot";

// DIZIONARIO ERRORI COMPLETO (6 LINGUE)
const i18n = {
  'it': {
    title: "⚠️ Attivazione Fallita",
    body: `Esiste già un account attivo per la Partita IVA ${vat}.`,
    reason: "Per motivi di sicurezza, non è possibile sovrascrivere un'istanza esistente.",
    action: "Se hai bisogno di assistenza o vuoi resettare l'account, contatta il supporto.",
    btn_support: "🆘 Contatta Supporto"
  },
  'en': {
    title: "⚠️ Activation Failed",
    body: `An active account already exists for VAT ID ${vat}.`,
    reason: "For security reasons, overwriting an existing instance is not allowed.",
    action: "If you need assistance or wish to reset the account, please contact support.",
    btn_support: "🆘 Contact Support"
  },
  'fr': {
    title: "⚠️ Échec de l'Activation",
    body: `Un compte actif existe déjà pour le numéro de TVA ${vat}.`,
    reason: "Pour des raisons de sécurité, il n'est pas permis d'écraser une instance existante.",
    action: "Si vous avez besoin d'aide ou souhaitez réinitialiser le compte, contactez le support.",
    btn_support: "🆘 Contacter le Support"
  },
  'de': {
    title: "⚠️ Aktivierung Fehlgeschlagen",
    body: `Es existiert bereits ein aktives Konto für die USt-IdNr. ${vat}.`,
    reason: "Aus Sicherheitsgründen ist das Überschreiben einer bestehenden Instanz nicht gestattet.",
    action: "Wenn Sie Hilfe benötigen oder das Konto zurücksetzen möchten, wenden Sie sich bitte an den Support.",
    btn_support: "🆘 Support kontaktieren"
  },
  'es': {
    title: "⚠️ Activación Fallida",
    body: `Ya existe una cuenta activa para el NIF ${vat}.`,
    reason: "Por razones de seguridad, no se permite sobrescribir una instancia existente.",
    action: "Si necesitas asistencia o deseas restablecer la cuenta, contacta con el soporte.",
    btn_support: "🆘 Contactar Soporte"
  },
  'pt': {
    title: "⚠️ Falha na Ativação",
    body: `Já existe uma conta ativa para o NIF ${vat}.`,
    reason: "Por motivos de segurança, não é permitido sobrescrever uma instância existente.",
    action: "Se precisar de assistência ou desejar redefinir a conta, entre em contato com o suporte.",
    btn_support: "🆘 Contactar Suporte"
  }
};

const t = i18n[userLang.substring(0,2)] || i18n['it'];

// --- PAYLOAD 1: Per la WebApp (risposta al webhook) ---
// La WebApp si aspetta la risposta direttamente nel JSON principale
const webAppErrorPayload = {
  status: "error",
  error: {
    code: "DUPLICATE_INSTANCE",
    title: t.title,
    message: `${t.body}\n\n${t.reason}\n${t.action}`
  }
};

// --- PAYLOAD 2: Per Telegram (notifica in chat) ---
// Usa la chiave standard 'telegramPayload' come richiesto.
const telegramMessageText = `
⛔️ <b>ERRORE ATTIVAZIONE RILEVATO</b>

Un tentativo di attivazione è stato bloccato perché l'account per la P.IVA <code>${vat}</code> esiste già.

<b>Azione intrapresa:</b>
L'utente è stato notificato tramite la WebApp.

Se ritieni sia un errore o l'utente necessita di un reset, contatta il supporto.
`;

const telegramPayload = {
    chat_id: chatId,
    text: telegramMessageText,
    parse_mode: "HTML",
    reply_markup: {
        inline_keyboard: [[{
            text: t.btn_support,
            url: SUPPORT_BOT_URL
        }]]
    }
};

// --- RETURN Combinato CORRETTO ---
return {
    json: {
        ...webAppErrorPayload, // Le chiavi 'status' ed 'error' sono al primo livello
        telegramPayload: telegramPayload // La chiave 'telegramPayload' è una chiave separata
    }
};

