// NODO: Activation_Message_Editor (Hybrid Fix)
// VERSIONE: 3.1 - Supporto WebApp (No Callback) + Telegram Edit
// OBIETTIVO: Gestire sia l'editing del messaggio (se da Bot) sia l'invio nuovo (se da WebApp)

// ═══════════════════════════════════════════════════════════════════════════
// 1. RECUPERO INPUT SICURO
// ═══════════════════════════════════════════════════════════════════════════
const input = $input.first().json;

// Supporto per diverse strutture di input (adattatore implicito)
const userData = input.owner_data || input.body?.data?.owner_data;
// Cerchiamo callback_details in profondità, con fallback a null
const callbackDetails = input.user_request?.callback_details || input.body?.data?.user_request?.callback_details || null;

if (!userData) {
    throw new Error("Dati utente (owner_data) non trovati nell'input.");
}

// Estrazione dati chiave
const chatId = userData.chat_id;
const userName = userData.name || 'Utente';
const companyName = userData.ragione_sociale || 'la tua azienda';
const langString = userData.lenguage || 'it';
const languageCode = langString.substring(0, 2).toLowerCase(); 

// ID Messaggio da editare (se esiste)
const messageToEditId = callbackDetails ? callbackDetails.message_to_edit_id : null;

// ═══════════════════════════════════════════════════════════════════════════
// 2. MAPPING LINGUA
// ═══════════════════════════════════════════════════════════════════════════
const languageMap = {
  'it': 'Italiano', 'en': 'English', 'fr': 'Français',
  'de': 'Deutsch', 'es': 'Español', 'pt': 'Português'
};
const detectedLanguage = languageMap[languageCode] || 'Italiano';

// ═══════════════════════════════════════════════════════════════════════════
// 3. DIZIONARIO MULTILINGUA
// ═══════════════════════════════════════════════════════════════════════════
const translations = {
  'Italiano': {
    title: "✅ <b>MOTORE SITEBOS AVVIATO!</b>",
    greeting: "Ciao <b>{userName}</b>, benvenuto a bordo! 👋",
    confirmation: "L'istanza per <i>{companyName}</i> è ora <b>attiva</b>.",
    analysis: "🤖 <b>Intelligenza in Azione...</b>\nI nostri analisti AI stanno studiando i dati della tua azienda per preparare il tuo assistente personale.",
    timing: "⏱ <b>Tempo stimato:</b> Circa 4-5 minuti.\nPuoi attendere nella WebApp o chiudere: ti avviserò qui quando avrò finito.",
    closing: "A tra pochissimo! 🚀"
  },
  'English': {
    title: "✅ <b>SITEBOS ENGINE STARTED!</b>",
    greeting: "Hello <b>{userName}</b>, welcome aboard! 👋",
    confirmation: "The instance for <i>{companyName}</i> is now <b>active</b>.",
    analysis: "🤖 <b>Intelligence in Action...</b>\nOur AI analysts are studying your company data to prepare your personal assistant.",
    timing: "⏱ <b>Estimated time:</b> About 4-5 minutes.\nYou can wait in the WebApp or close it: I will notify you here when done.",
    closing: "See you very soon! 🚀"
  },
  // ... (altre lingue se vuoi, usa il fallback inglese per brevità)
};

const t = translations[detectedLanguage] || translations['English'] || translations['Italiano'];

// ═══════════════════════════════════════════════════════════════════════════
// 4. COSTRUZIONE MESSAGGIO
// ═══════════════════════════════════════════════════════════════════════════
const newText = 
  `${t.title}\n\n` +
  `${t.greeting.replace('{userName}', userName)}\n` +
  `${t.confirmation.replace('{companyName}', companyName)}\n\n` +
  `───────────────\n\n` +
  `${t.analysis}\n\n` +
  `${t.timing}\n\n` +
  `───────────────\n\n` +
  `${t.closing}`;

// ═══════════════════════════════════════════════════════════════════════════
// 5. DETERMINA METODO (EDIT vs SEND)
// ═══════════════════════════════════════════════════════════════════════════
let telegramApiPayload = {};

if (messageToEditId) {
    // CASO A: Arrivo da click su bottone Telegram -> EDIT
    telegramApiPayload = {
      method: "editMessageText",
      chat_id: chatId,
      message_id: messageToEditId,
      text: newText,
      parse_mode: "HTML",
      reply_markup: { inline_keyboard: [] } // Rimuove bottoni vecchi
    };
} else {
    // CASO B: Arrivo da WebApp (Processor) -> SEND NEW
    telegramApiPayload = {
      method: "sendMessage",
      chat_id: chatId,
      text: newText,
      parse_mode: "HTML"
      // Niente reply_markup per ora, è un messaggio informativo
    };
}

// ═══════════════════════════════════════════════════════════════════════════
// 6. RETURN
// ═══════════════════════════════════════════════════════════════════════════
return [{
  json: {
    ...input, // Mantieni i dati originali per i nodi successivi
    telegramApiPayload: telegramApiPayload
  }
}];

// NODO: HoneyPot_WebApp_Notifier (Dashboard Link Edition)
// VERSIONE: 3.0 - Single Entry Point
// OBIETTIVO: Notificare il completamento e fornire UNICO accesso alla Dashboard.

const input = $input.first().json;
const ownerData = input.owner_data;
// Gestione robusta dei callback details (potrebbero non esserci se flusso webapp, ma qui stiamo editando un messaggio esistente)
const callbackDetails = input.user_request?.callback_details || {};

if (!ownerData) {
    throw new Error("Dati 'owner_data' mancanti.");
}

// ═══════════════════════════════════════════════════════════════════════════
// 1. CONFIGURAZIONE URL DASHBOARD
// ═══════════════════════════════════════════════════════════════════════════
const DASHBOARD_BASE_URL = "https://dashboard.trinai.it/sitebos";

// Estrazione Dati
const vat = ownerData.vat_number;
const chatId = ownerData.chat_id;
const token = ownerData.access_token; // FONDAMENTALE per il login automatico
const companyName = ownerData.ragione_sociale;
const langCode = ownerData.lenguage || 'it';
const userName = ownerData.name;

// Costruzione URL Sicuro
const dashboardUrl = `${DASHBOARD_BASE_URL}?vat=${vat}&owner=${chatId}&token=${token}&lang=${langCode.substring(0,2)}&ragione_sociale=${encodeURIComponent(companyName)}`;

// ID Messaggio da editare (se arriviamo dal flusso telegram originale)
const messageToEditId = callbackDetails.message_to_edit_id;

// ═══════════════════════════════════════════════════════════════════════════
// 2. MAPPING LINGUA
// ═══════════════════════════════════════════════════════════════════════════
const langMap = { 'it':'Italiano', 'en':'English', 'fr':'Français', 'de':'Deutsch', 'es':'Español', 'pt':'Português' };
const normalizedLang = langMap[langCode.substring(0,2)] || 'Italiano';

// ═══════════════════════════════════════════════════════════════════════════
// 3. DIZIONARIO (Focus su "Sistema Pronto")
// ═══════════════════════════════════════════════════════════════════════════
const i18n = {
  'Italiano': {
    title: "🚀 <b>SISTEMA OPERATIVO ATTIVO</b>",
    greeting: "Ottime notizie, <b>{userName}</b>!",
    body: "L'analisi AI è terminata e la tua istanza SiteBoS è stata configurata completamente.",
    instruction: "Accedi ora al tuo <b>Manager Desk</b>. Da lì potrai controllare la Knowledge Base, gestire i prodotti e vedere l'agenda.",
    btn_dashboard: "🎛️ Vai alla Dashboard"
  },
  'English': {
    title: "🚀 <b>OPERATING SYSTEM ACTIVE</b>",
    greeting: "Great news, <b>{userName}</b>!",
    body: "AI analysis is complete and your SiteBoS instance is fully configured.",
    instruction: "Access your <b>Manager Desk</b> now. From there you can check the Knowledge Base, manage products, and view the agenda.",
    btn_dashboard: "🎛️ Go to Dashboard"
  },
  'Français': {
    title: "🚀 <b>SYSTÈME D'EXPLOITATION ACTIF</b>",
    greeting: "Excellente nouvelle, <b>{userName}</b> !",
    body: "L'analyse IA est terminée et votre instance SiteBoS est entièrement configurée.",
    instruction: "Accédez maintenant à votre <b>Bureau de Gestion</b>. De là, vous pourrez contrôler la Base de Connaissances, gérer les produits et voir l'agenda.",
    btn_dashboard: "🎛️ Aller au Tableau de Bord"
  },
  'Deutsch': {
    title: "🚀 <b>BETRIEBSSYSTEM AKTIV</b>",
    greeting: "Gute Nachrichten, <b>{userName}</b>!",
    body: "Die KI-Analyse ist abgeschlossen und Ihre SiteBoS-Instanz ist vollständig konfiguriert.",
    instruction: "Greifen Sie jetzt auf Ihren <b>Manager Desk</b> zu. Von dort aus können Sie die Wissensdatenbank prüfen, Produkte verwalten und die Agenda einsehen.",
    btn_dashboard: "🎛️ Zum Dashboard"
  },
  'Español': {
    title: "🚀 <b>SISTEMA OPERATIVO ACTIVO</b>",
    greeting: "¡Excelentes noticias, <b>{userName}</b>!",
    body: "El análisis de IA ha finalizado y tu instancia SiteBoS está totalmente configurada.",
    instruction: "Accede ahora a tu <b>Escritorio de Gestión</b>. Desde allí podrás controlar la Base de Conocimiento, gestionar productos y ver la agenda.",
    btn_dashboard: "🎛️ Ir al Dashboard"
  },
  'Português': {
    title: "🚀 <b>SISTEMA OPERACIONAL ATIVO</b>",
    greeting: "Ótimas notícias, <b>{userName}</b>!",
    body: "A análise de IA foi concluída e sua instância SiteBoS está totalmente configurada.",
    instruction: "Acesse agora sua <b>Mesa de Gerenciamento</b>. De lá, você poderá verificar a Base de Conhecimento, gerenciar produtos e ver a agenda.",
    btn_dashboard: "🎛️ Ir para o Painel"
  }
};

const t = i18n[normalizedLang] || i18n['Italiano'];

// ═══════════════════════════════════════════════════════════════════════════
// 4. COSTRUZIONE MESSAGGIO
// ═══════════════════════════════════════════════════════════════════════════
const messageText = `
${t.title}

${t.greeting.replace('{userName}', userName)}
${t.body}

${t.instruction}
`;

// Unico Bottone per la Dashboard
const replyMarkup = {
    inline_keyboard: [
        [{
            text: t.btn_dashboard,
            url: dashboardUrl
        }]
    ]
};

// ═══════════════════════════════════════════════════════════════════════════
// 5. DETERMINA METODO (EDIT vs SEND)
// ═══════════════════════════════════════════════════════════════════════════
let telegramApiPayload = {};

if (messageToEditId) {
    // Se c'era un messaggio di attesa, lo aggiorniamo
    telegramApiPayload = {
      method: "editMessageText",
      chat_id: chatId,
      message_id: messageToEditId,
      text: messageText,
      parse_mode: "HTML",
      reply_markup: replyMarkup
    };
} else {
    // Fallback: inviamo un nuovo messaggio (utile per debug o flussi anomali)
    telegramApiPayload = {
      method: "sendMessage",
      chat_id: chatId,
      text: messageText,
      parse_mode: "HTML",
      reply_markup: replyMarkup
    };
}

// ═══════════════════════════════════════════════════════════════════════════
// 6. OUTPUT
// ═══════════════════════════════════════════════════════════════════════════
return [{
    json: {
        ...input, // Passiamo tutto l'input ai nodi successivi (Build_Success_Payload)
        telegramPayload: telegramApiPayload
    }
}];

// NODO: Finalize_Provisioning (Enterprise Edition v3.5)
// OBIETTIVO: Salvare TUTTI i dati originali + Social + Crediti dallo Stakeholder

const input = $input.first().json;

// --- MAPPING INPUT ---
const req = input.body.data || input.body; 
const rawData = req.owner_data;
const existingStakeholder = input.stakeholder; // Per recuperare i 2000 crediti

function generateUUID() {
    return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
        var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
        return v.toString(16);
    });
}

// 1. NORMALIZZAZIONE LINGUA E VAT
const userLang = rawData.language || "it";
const normalizedLang = (userLang.substring(0,2) === 'it') ? 'Italiano' : 'English';
const countryPrefixMap = { 'Italiano':'IT', 'English':'GB' };
const targetPrefix = countryPrefixMap[normalizedLang] || 'IT';

let cleanVat = rawData.vat_number.toUpperCase().replace(/[^A-Z0-9]/g, '');
if (/^[0-9]+$/.test(cleanVat)) {
    cleanVat = targetPrefix + cleanVat;
}

const cleanChatId = parseInt(req.chat_id || req.user_id, 10);
if (isNaN(cleanChatId)) throw new Error("Chat ID invalido");

const accessToken = generateUUID();

// 2. COSTRUZIONE OWNER_DATA INTEGRALE
const ownerData = {
    user_id: cleanVat,
    chat_id: cleanChatId,
    access_token: accessToken,
    group_id: null,
    user_name: "",
    vat_number: cleanVat,
    gemini_key: rawData.gemini_key,
    bot_key: "",
    path: "",
    name: rawData.name,
    surname: rawData.surname,
    email: rawData.email,
    phone: rawData.phone,
    ragione_sociale: rawData.ragione_sociale,
    indirizzo: rawData.indirizzo,
    fiscal_code: rawData.fiscal_code,
    sdi_pec: rawData.sdi_pec,

    // --- DATI WEB & SOCIAL (Preservati) ---
    site: rawData.site || "",
    linkedin_page: rawData.linkedin_page || "",
    facebook_page: rawData.facebook_page || "",
    instagram_page: rawData.instagram_page || "",
    twitter_page: rawData.twitter_page || "",

    sector: rawData.sector,
    business_description: rawData.what_we_do,
    ai_goal: rawData.main_goal,

    // --- DATI KYC ---
    kyc_details: rawData.kyc_details || {}, 

    subscription_plan: rawData.plan || "Pioneer Trial",
    subscription_status: "Pending_Activation",

   // --- FIX CREDITI: 600 Crediti Omaggio Pioneer Trial (Policy Attuale) ---
credits_balance: existingStakeholder?.commercial_profile?.credit_balance?.available_credits || 600,

// Abilitazione immediata e out-of-the-box di SuperVisor (Certificatore)
esposizione_prezzi: true, 
certifier_enabled: true,
subscription_certificator: true,

    model_choice: "https://generativelanguage.googleapis.com/v1beta/models/gemini-flash-lite-latest:generateContent",
    lenguage: normalizedLang,
    owner_unavailable_time: "21-7",
    operator_unavailable_time: "19-9",

    // --- OPERATORS (Ripristinato) ---
    operators: [{
        OperatorName: `${rawData.name} ${rawData.surname}`,
        OperatorChatID: cleanChatId,
        OperatorLenguage: normalizedLang,
