// NODO: Set_Loading_State (WebApp Mode)
// VERSIONE: 3.0 - WebApp Pure (Force SendMessage)
// OBIETTIVO: Inviare un NUOVO messaggio di notifica ("Inizializzazione...")
//            poiché l'utente arriva dalla WebApp e non c'è un messaggio da editare.

// ═══════════════════════════════════════════════════════════════════════════
// 1. RECUPERO DATI
// ═══════════════════════════════════════════════════════════════════════════
const item = $input.first().json;
const ownerData = item.owner_data || {};
const userRequest = item.user_request || {};

// Cerchiamo il Chat ID nel posto più sicuro (owner_data)
const chatId = ownerData.chat_id || (userRequest.chat && userRequest.chat.group_id);

if (!chatId) {
    throw new Error("Chat ID non trovato in owner_data o user_request.");
}

// Cerchiamo il Thread ID (Topic) se esiste, per non spammare nella chat generale
const threadId = (userRequest.chat && userRequest.chat.thread_id) || ownerData.thread_id || null;

// Recupero lingua (owner_data ha priorità es. "Italiano", userRequest ha "it")
const rawLang = ownerData.lenguage || userRequest.sender?.language_code || 'it';

// ═══════════════════════════════════════════════════════════════════════════
// 2. DIZIONARIO MULTILINGUA
// ═══════════════════════════════════════════════════════════════════════════
// Mappiamo l'input (che può essere "it" o "Italiano") alle chiavi del dizionario
let langKey = 'Italiano'; // Default
const lowerLang = String(rawLang).toLowerCase();

if (lowerLang.startsWith('it')) langKey = 'Italiano';
else if (lowerLang.startsWith('en')) langKey = 'English';
else if (lowerLang.startsWith('fr')) langKey = 'Français';
else if (lowerLang.startsWith('de')) langKey = 'Deutsch';
else if (lowerLang.startsWith('es')) langKey = 'Español';
else if (lowerLang.startsWith('pt')) langKey = 'Português';

const translations = {
  'Italiano': {
    title: "⚙️ <b>Configurazione Avviata</b>",
    message: "Stiamo costruendo la tua architettura AI.",
    explanation: "Il processo è automatico e richiede circa 2 minuti. Riceverai una notifica qui appena terminato."
  },
  'English': {
    title: "⚙️ <b>Configuration Started</b>",
    message: "We are building your AI architecture.",
    explanation: "The process is automatic and takes about 2 minutes. You will be notified here once finished."
  },
  'Français': {
    title: "⚙️ <b>Configuration Lancée</b>",
    message: "Nous construisons votre architecture IA.",
    explanation: "Le processus est automatique et prend environ 2 minutes. Vous serez notifié ici une fois terminé."
  },
  'Deutsch': {
    title: "⚙️ <b>Konfiguration Gestartet</b>",
    message: "Wir bauen Ihre KI-Architektur auf.",
    explanation: "Der Vorgang ist automatisch und dauert ca. 2 Minuten. Sie werden hier benachrichtigt, sobald er abgeschlossen ist."
  },
  'Español': {
    title: "⚙️ <b>Configuración Iniciada</b>",
    message: "Estamos construyendo tu arquitectura de IA.",
    explanation: "El proceso es automático y tarda unos 2 minutos. Se te notificará aquí cuando termine."
  },
  'Português': {
    title: "⚙️ <b>Configuração Iniciada</b>",
    message: "Estamos construindo sua arquitetura de IA.",
    explanation: "O processo é automático e leva cerca de 2 minutos. Você será notificado aqui assim que terminar."
  }
};

const t = translations[langKey] || translations['Italiano'];

// ═══════════════════════════════════════════════════════════════════════════
// 3. COSTRUZIONE DEL PAYLOAD (sendMessage)
// ═══════════════════════════════════════════════════════════════════════════
const messageText = `${t.title}\n\n${t.message}\n<i>${t.explanation}</i>`;

const telegramApiPayload = {
    method: "sendMessage",
    chat_id: chatId,
    text: messageText,
    parse_mode: "HTML"
};

// Se siamo in un topic, aggiungiamo il thread_id
if (threadId) {
    telegramApiPayload.message_thread_id = threadId;
}

// ═══════════════════════════════════════════════════════════════════════════
// 4. RETURN
// ═══════════════════════════════════════════════════════════════════════════
return [{
    json: {
        ...item,
        telegramApiPayload: telegramApiPayload,
        status_log: "webapp_init_notification_sent"
    }
}];

// NODO: Global_ID_Rewriter
// OBIETTIVO: Sostituire tutti i callback_data semantici (lunghi e rischiosi)
//            con ID tecnici (brevi, univoci e sicuri per Telegram).

const item = $input.first().json;

// Recuperiamo il catalogo (gestiamo se arriva come oLabel o service_catalog_setup)
let catalogWrapper = item.oLabel || item.service_catalog_setup;

if (!catalogWrapper || !catalogWrapper.categories) {
  throw new Error("Struttura catalogo non trovata in oLabel o service_catalog_setup");
}

// Set per garantire univocità assoluta durante la generazione
const generatedIds = new Set();

// Funzione generatrice ID (Prefisso + 8 char alfanumerici upper)
function generateUniqueId(prefix) {
  let id;
  do {
    // Genera stringa random base36 e prendi 8 caratteri
    const uniquePart = Math.random().toString(36).substring(2, 10).toUpperCase();
    id = `${prefix}_${uniquePart}`;
  } while (generatedIds.has(id)); // Se per assurdo esiste già, rigenera

  generatedIds.add(id);
  return id;
}

// ITERAZIONE E RISCRITTURA
const newCategories = catalogWrapper.categories.map(cat => {

  // 1. Riscrivi ID Categoria
  // Da: "PIATTAFORME_TBOS_SISTEMA_OPERATIVO..." (Troppo lungo)
  // A:  "CAT_9X8Y7Z6W" (Sicuro)
  const newCatId = generateUniqueId("CAT");

  // Mappiamo le sottocategorie
  const newSubcategories = (cat.subcategories || []).map(sub => {

    // 2. Riscrivi ID Sottocategoria/Servizio
    // Da: "LICENZA_BASE_TBOS_ANNUALITA..." (Troppo lungo)
    // A:  "SVC_A1B2C3D4" (Sicuro)
    const newSubId = generateUniqueId("SVC"); // Usa 'PRD' se preferisci distinzione prodotti

    return {
      ...sub,
      callback_data: newSubId,
      // Salviamo il vecchio callback come "legacy_slug" per debug/riferimento (opzionale)
      original_slug: sub.callback_data 
    };
  });

  return {
    ...cat,
    callback_data: newCatId,
    original_slug: cat.callback_data,
    subcategories: newSubcategories
  };
});

// Aggiorniamo l'oggetto originale
catalogWrapper.categories = newCategories;

// Output
return [{
  json: {
    ...item,
    // Sovrascriviamo oLabel o service_catalog con la versione "Sanitizzata"
    oLabel: item.oLabel ? catalogWrapper : undefined,
    service_catalog_setup: item.service_catalog_setup ? catalogWrapper : undefined,

    // Metadati per debug
    ids_generated_count: generatedIds.size,
    sanitization_status: "COMPLETED_SECURE"
  }
}];

