// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Perfect_Dashboard_Welcome (V7.6 Surgical Fix)
// DESC: Allineato a 📝 Prep: Dynamic Agent Selection
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const owner = item.owner_data || {};
const baseUrl = item.urlMiniApp || "https://trinaibusinessoperatingsystem.github.io/SiteBoS-MiniApp/telegram_control/";
const credits = owner.credits_balance || 0;
const callbackQuery = item.user_request || {};

const chatId = (item.user_request.owner_id) || owner.chat_id;
const messageIdToEdit = (callbackQuery.message_id) || null;

// --- LOGICA CONDIVISA UTENTE DI TEST ---
const isTestUser = String(chatId) === "2041408875";

// --- LOGICA SIGNATURE ASH ---
function generateSignature(str, key) {
    let hash = 0; const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        const char = combined.charCodeAt(i);
        hash = ((hash << 5) - hash) + char; hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const ts = Date.now().toString();
const payloadASH = `${chatId}|${ts}|ef4aece4-9ec0-4026-a7a7-328562bcbdf6`;
const ash = `${Buffer.from(payloadASH).toString('base64')}.${generateSignature(payloadASH, SECRET_KEY)}`;

// --- LOGICA SUPERVISOR (Attiva Out-Of-The-Box - No Costo Attivazione) ---
const COSTO_USO_CERT = 1;
const URL_DASHBOARD = "https://dashboard.trinai.it/";

let labelSup = "🛡️ SuperVisor";
let cbSup = "get_active";
let urlSup = null;

if (credits < COSTO_USO_CERT) {
    labelSup = "⚠️ Credito Insuf.";
    urlSup = URL_DASHBOARD;
}

const t = {
    header: `🛠️ <b>SiteBoS Assistant KeyBoard</b>`,
    entity: `🏢 <b>${(owner.ragione_sociale || 'PRIVATE_TENANT').toUpperCase()}</b>`,
    user: `👤 OPERATORE: <b>${owner.name} ${owner.surname}</b>`,
    status: `📊 STATO: <b>OPERATIVO</b>`,
    balance: `🔋 DISPONIBILITÀ: <b>${credits} CREDITI</b>`,
    gdpr: `🔐 <b>PROTOCOLLO SICUREZZA & PRIVACY</b>\n<i>In conformità al GDPR (Reg. UE 2016/679) e al principio di minimizzazione dei dati, tutti i messaggi inviati a questa chat vengono rimossi ISTANTANEAMENTE per garantirne la totale riservatezza ed evitarne la conservazione sui server di Telegram.</i>`
};

// --- COSTRUZIONE DINAMICA TASTIERA MONOCOLONNA ---
const buttons = [];

buttons.push([{ text: "🏢 Identità Aziendale", web_app: { url: `${baseUrl}identity_hub.html?ash=${ash}&msg=${messageIdToEdit}` } }]);
buttons.push([{ text: "📋 Gestione Aziendale", web_app: { url: `${baseUrl}catalog.html?ash=${ash}&msg=${messageIdToEdit}` } }]);
buttons.push([{ text: labelSup, callback_data: cbSup, ...(urlSup && { url: urlSup }) }]);
buttons.push([{ text: "📣 Marketing", callback_data: "m_mkt" }]);
buttons.push([{ text: "👥 Team", callback_data: "m_team" }]);

if (isTestUser) {
    buttons.push([{ text: "💸 Acquisti", web_app: { url: `${baseUrl}new-insert.html?ash=${ash}&msg=${messageIdToEdit}` } }]);
    buttons.push([{ text: "⏳ Operazioni", callback_data: "tm_menu" }]);
    buttons.push([{ text: "💬 Comunicazioni", web_app: { url: `${baseUrl}comunication_hub.html?ash=${ash}&msg=${messageIdToEdit}` } }]);
    buttons.push([{ text: "📊 Intelligence", callback_data: "int_" }]);
}

buttons.push([{ text: "🔄 Sync", callback_data: "open_agent_control_center" }]);

// Costruzione testo con andate a capo native
const formattedText = `${t.header}\n━━━━━━━━━━━━━━━━━━━━\n${t.entity}\n${t.user}\n${t.status}\n${t.balance}\n━━━━━━━━━━━━━━━━━━━━\n${t.gdpr}`;

return [{
    json: {
        ...item,
        telegramApiPayload: {
            method: messageIdToEdit ? "editMessageText" : "sendMessage",
            chat_id: chatId,
            ...(messageIdToEdit && { message_id: messageIdToEdit }),
            text: formattedText,
            parse_mode: "HTML",
            reply_markup: { inline_keyboard: buttons }
        }
    }
}];

// NODO: Build_Success_Payload
// OBIETTIVO: Restituire i dati per il redirect alla Dashboard

const input = $input.first().json;

// Recuperiamo i dati (assicurati che owner_data sia arrivato fin qui)
const ownerData = input.owner_data; 

if (!ownerData) throw new Error("Dati owner persi nel flusso.");

return {
  json: {
    // Flag di successo
    status: "success",

    // Payload per processor_logic.js -> result.owner_data
    owner_data: {
        vat_number: ownerData.vat_number,
        chat_id: ownerData.chat_id,
        ragione_sociale: ownerData.ragione_sociale,
        // Questo token serve per il login automatico nella Dashboard
        access_token: ownerData.access_token 
    }
  }
};
